@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1 class="mb-3">Project Board</h1>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Stats bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="stats-card bg-light p-2 rounded text-center"><strong>Total</strong><br />@allTasks.Count</div></div>
        <div class="col"><div class="stats-card bg-light p-2 rounded text-center"><strong>To Do</strong><br />@CountByStatus("To Do")</div></div>
        <div class="col"><div class="stats-card bg-light p-2 rounded text-center"><strong>In Progress</strong><br />@CountByStatus("In Progress")</div></div>
        <div class="col"><div class="stats-card bg-light p-2 rounded text-center"><strong>Done</strong><br />@CountByStatus("Done")</div></div>
        <div class="col"><div class="stats-card bg-light p-2 rounded text-center text-danger"><strong>Overdue</strong><br />@allTasks.Count(t => t.DueDate.Date < DateTime.Today)</div></div>
    </div>

    <!-- Search -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…" @bind="searchText" @bind:event="oninput" />
    </div>

    <!-- Columns -->
    <div class="row g-3 board-columns">
        @foreach (var column in columns)
        {
            var colTasks = GetFilteredTasks(column);
            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <span class="fw-bold">@column</span>
                        <span class="badge bg-secondary">@colTasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height:65vh;">
                        @foreach (var task in colTasks)
                        {
                            <div class="card task-card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @PriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (column != columns[0])
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill" disabled="@isBusy" @onclick="() => MoveTask(task, -1)">← Move Left</button>
                                        }
                                        @if (column != columns[^1])
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill" disabled="@isBusy" @onclick="() => MoveTask(task, 1)">Move Right →</button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (addingColumn == column)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2 d-flex flex-column gap-2">
                                    <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="newTitle" />
                                    <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="newAssignee" />
                                    <select class="form-select form-select-sm" @bind="newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm" @bind="newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill" disabled="@isBusy" @onclick="SaveNewTask">Save</button>
                                        <button class="btn btn-outline-secondary btn-sm flex-fill" @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => StartAdd(column)">+ Add Task</button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private bool isBusy;
    private string? errorMessage;
    private string searchText = string.Empty;

    // Add-task form state
    private string? addingColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private int CountByStatus(string status) =>
        allTasks.Count(t => t.Status == status);

    private List<TaskItem> GetFilteredTasks(string status) =>
        allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(searchText) ||
                         t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTask(TaskItem task, int direction)
    {
        int idx = Array.IndexOf(columns, task.Status);
        int newIdx = idx + direction;
        if (newIdx < 0 || newIdx >= columns.Length) return;

        isBusy = true;
        try
        {
            var newStatus = columns[newIdx];
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Replace the item in-place with updated status
            int pos = allTasks.FindIndex(t => t.Id == task.Id);
            if (pos >= 0)
                allTasks[pos] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            isBusy = false;
        }
    }

    private void StartAdd(string column)
    {
        addingColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => addingColumn = null;

    private async Task SaveNewTask()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || addingColumn is null) return;

        isBusy = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            // The service creates with default status; override to match the column
            if (created.Status != addingColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, addingColumn);
                created = created with { Status = addingColumn };
            }
            allTasks.Add(created);
            addingColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isBusy = false;
        }
    }
}

.board-columns {
    min-height: 60vh;
}

.task-card {
    transition: box-shadow 0.15s;
}

.task-card:hover {
    box-shadow: 0 .25rem .75rem rgba(0, 0, 0, .15) !important;
}

.stats-card {
    border: 1px solid #dee2e6;
}

